        let mut timestamp: Value = self.safe_integer_k(message.clone(), "ts", &[]);
        let mut tick: Value = self.safe_value_k(message.clone(), "tick", &[Value::Map({
            let mut m = indexmap::IndexMap::new();
            m
        })]);
